unit lipdecide;

interface

uses globals;

function REALCOMPARE(A, B: real): COMPTYPE;
procedure DECIDE;

implementation

uses Math;

{ REALCOMPARE: Compare two reals with 6 significant digits precision }
function REALCOMPARE(A, B: real): COMPTYPE;
var
  absA, absB, maxVal, epsilon: real;
begin
  absA := Abs(A);
  absB := Abs(B);

  if absA > absB then
    maxVal := absA
  else
    maxVal := absB;

  { Use relative epsilon based on magnitude for 6 significant digits }
  if maxVal > 0 then
    epsilon := maxVal * 1e-6
  else
    epsilon := 1e-6;

  if Abs(A - B) < epsilon then
    REALCOMPARE := EQ
  else if A < B then
    REALCOMPARE := LT
  else
    REALCOMPARE := GT;
end;

{ Helper: Calculate distance between two points }
function Distance(x1, y1, x2, y2: real): real;
begin
  Distance := Sqrt(Sqr(x2 - x1) + Sqr(y2 - y1));
end;

{ Helper: Calculate area of triangle given three points }
function TriangleArea(x1, y1, x2, y2, x3, y3: real): real;
begin
  { Use cross product formula: |0.5 * ((x2-x1)(y3-y1) - (x3-x1)(y2-y1))| }
  TriangleArea := Abs(0.5 * ((x2 - x1) * (y3 - y1) - (x3 - x1) * (y2 - y1)));
end;

{ Helper: Calculate angle at vertex (x2,y2) formed by points (x1,y1), (x2,y2), (x3,y3) }
{ Returns angle in radians, or -1 if undefined (coincident points) }
function CalcAngle(x1, y1, x2, y2, x3, y3: real): real;
var
  dx1, dy1, dx2, dy2, len1, len2, dotProduct, cosAngle: real;
begin
  dx1 := x1 - x2;
  dy1 := y1 - y2;
  dx2 := x3 - x2;
  dy2 := y3 - y2;

  len1 := Sqrt(Sqr(dx1) + Sqr(dy1));
  len2 := Sqrt(Sqr(dx2) + Sqr(dy2));

  { Check if vertex coincides with either endpoint }
  if (REALCOMPARE(len1, 0) = EQ) or (REALCOMPARE(len2, 0) = EQ) then
  begin
    CalcAngle := -1; { Undefined }
    Exit;
  end;

  dotProduct := dx1 * dx2 + dy1 * dy2;
  cosAngle := dotProduct / (len1 * len2);

  { Clamp to [-1, 1] to handle floating point errors }
  if cosAngle > 1.0 then
    cosAngle := 1.0
  else if cosAngle < -1.0 then
    cosAngle := -1.0;

  CalcAngle := ArcCos(cosAngle);
end;

{ Helper: Check if three points can be contained in or on a circle of given radius }
function CanFitInCircle(x1, y1, x2, y2, x3, y3, radius: real): boolean;
var
  d12, d23, d13, a, b, c, s, area, circumRadius: real;
begin
  { Calculate distances between points }
  d12 := Distance(x1, y1, x2, y2);
  d23 := Distance(x2, y2, x3, y3);
  d13 := Distance(x1, y1, x3, y3);

  { If all points are collinear or nearly so, check if they fit on diameter }
  area := TriangleArea(x1, y1, x2, y2, x3, y3);
  if REALCOMPARE(area, 0) = EQ then
  begin
    { Collinear: need diameter >= longest distance }
    if (REALCOMPARE(d12, d23) <> LT) and (REALCOMPARE(d12, d13) <> LT) then
      CanFitInCircle := REALCOMPARE(d12 / 2, radius) <> GT
    else if REALCOMPARE(d23, d13) <> LT then
      CanFitInCircle := REALCOMPARE(d23 / 2, radius) <> GT
    else
      CanFitInCircle := REALCOMPARE(d13 / 2, radius) <> GT;
    Exit;
  end;

  { Calculate circumradius using R = abc / 4A }
  a := d23;
  b := d13;
  c := d12;
  circumRadius := (a * b * c) / (4 * area);

  CanFitInCircle := REALCOMPARE(circumRadius, radius) <> GT;
end;

{ Helper: Distance from point (px,py) to line segment from (x1,y1) to (x2,y2) }
function DistanceToLine(px, py, x1, y1, x2, y2: real): real;
var
  dx, dy, t, projX, projY, lineLenSq: real;
begin
  dx := x2 - x1;
  dy := y2 - y1;
  lineLenSq := Sqr(dx) + Sqr(dy);

  { If endpoints are coincident, return distance to that point }
  if REALCOMPARE(lineLenSq, 0) = EQ then
  begin
    DistanceToLine := Distance(px, py, x1, y1);
    Exit;
  end;

  { Project point onto line and find distance }
  t := ((px - x1) * dx + (py - y1) * dy) / lineLenSq;

  { Clamp t to [0,1] for segment }
  if t < 0 then
    t := 0
  else if t > 1 then
    t := 1;

  projX := x1 + t * dx;
  projY := y1 + t * dy;

  DistanceToLine := Distance(px, py, projX, projY);
end;

{ Helper: Determine quadrant of point (x, y) }
function GetQuadrant(x, y: real): integer;
begin
  if REALCOMPARE(x, 0) <> LT then
  begin
    if REALCOMPARE(y, 0) <> LT then
      GetQuadrant := 1  { I: x >= 0, y >= 0 }
    else
      GetQuadrant := 4; { IV: x >= 0, y < 0 }
  end
  else
  begin
    if REALCOMPARE(y, 0) <> LT then
      GetQuadrant := 2  { II: x < 0, y >= 0 }
    else
      GetQuadrant := 3; { III: x < 0, y < 0 }
  end;
end;

{ Main DECIDE procedure }
procedure DECIDE;
var
  i, j, k: integer;
  dist, angle, area: real;
  quad, quadCount: integer;
  quadsUsed: array[1..4] of boolean;
  allTrue: boolean;

begin
  { Initialize outputs }
  for i := 1 to 15 do
  begin
    CMV[i] := false;
    FUV[i] := false;
  end;
  LAUNCH := false;

  { LIC 1: Two consecutive points distance > LENGTH1 }
  if NUMPOINTS >= 2 then
  begin
    for i := 1 to NUMPOINTS - 1 do
    begin
      dist := Distance(X[i], Y[i], X[i + 1], Y[i + 1]);
      if REALCOMPARE(dist, PARAMETERS.LENGTH1) = GT then
      begin
        CMV[1] := true;
        Break;
      end;
    end;
  end;

  { LIC 2: Three consecutive points cannot fit in circle of radius RADIUS1 }
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - 2 do
    begin
      if not CanFitInCircle(X[i], Y[i], X[i + 1], Y[i + 1], X[i + 2], Y[i + 2],
                           PARAMETERS.RADIUS1) then
      begin
        CMV[2] := true;
        Break;
      end;
    end;
  end;

  { LIC 3: Three consecutive points form angle < PI-EPSILON or > PI+EPSILON }
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - 2 do
    begin
      angle := CalcAngle(X[i], Y[i], X[i + 1], Y[i + 1], X[i + 2], Y[i + 2]);
      if angle >= 0 then { Angle is defined }
      begin
        if (REALCOMPARE(angle, PI - PARAMETERS.EPSILON) = LT) or
           (REALCOMPARE(angle, PI + PARAMETERS.EPSILON) = GT) then
        begin
          CMV[3] := true;
          Break;
        end;
      end;
    end;
  end;

  { LIC 4: Three consecutive points form triangle with area > AREA1 }
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - 2 do
    begin
      area := TriangleArea(X[i], Y[i], X[i + 1], Y[i + 1], X[i + 2], Y[i + 2]);
      if REALCOMPARE(area, PARAMETERS.AREA1) = GT then
      begin
        CMV[4] := true;
        Break;
      end;
    end;
  end;

  { LIC 5: Q_PTS consecutive points in more than QUADS quadrants }
  if NUMPOINTS >= PARAMETERS.Q_PTS then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.Q_PTS + 1 do
    begin
      for j := 1 to 4 do
        quadsUsed[j] := false;

      for j := i to i + PARAMETERS.Q_PTS - 1 do
      begin
        quad := GetQuadrant(X[j], Y[j]);
        quadsUsed[quad] := true;
      end;

      quadCount := 0;
      for j := 1 to 4 do
        if quadsUsed[j] then
          quadCount := quadCount + 1;

      if quadCount > PARAMETERS.QUADS then
      begin
        CMV[5] := true;
        Break;
      end;
    end;
  end;

  { LIC 6: Two consecutive points with X[j] - X[i] < 0 }
  if NUMPOINTS >= 2 then
  begin
    for i := 1 to NUMPOINTS - 1 do
    begin
      if REALCOMPARE(X[i + 1] - X[i], 0) = LT then
      begin
        CMV[6] := true;
        Break;
      end;
    end;
  end;

  { LIC 7: N_PTS consecutive points with one point distance > DIST from line }
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.N_PTS + 1 do
    begin
      { Check if first and last points are identical }
      if (REALCOMPARE(X[i], X[i + PARAMETERS.N_PTS - 1]) = EQ) and
         (REALCOMPARE(Y[i], Y[i + PARAMETERS.N_PTS - 1]) = EQ) then
      begin
        { Distance from coincident point to all other points }
        for j := i + 1 to i + PARAMETERS.N_PTS - 2 do
        begin
          dist := Distance(X[j], Y[j], X[i], Y[i]);
          if REALCOMPARE(dist, PARAMETERS.DIST) = GT then
          begin
            CMV[7] := true;
            Break;
          end;
        end;
      end
      else
      begin
        { Distance from intermediate points to line }
        for j := i + 1 to i + PARAMETERS.N_PTS - 2 do
        begin
          dist := DistanceToLine(X[j], Y[j], X[i], Y[i],
                                X[i + PARAMETERS.N_PTS - 1], Y[i + PARAMETERS.N_PTS - 1]);
          if REALCOMPARE(dist, PARAMETERS.DIST) = GT then
          begin
            CMV[7] := true;
            Break;
          end;
        end;
      end;

      if CMV[7] then
        Break;
    end;
  end;

  { LIC 8: Two points separated by K_PTS with distance > LENGTH1 }
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
    begin
      j := i + PARAMETERS.K_PTS + 1;
      dist := Distance(X[i], Y[i], X[j], Y[j]);
      if REALCOMPARE(dist, PARAMETERS.LENGTH1) = GT then
      begin
        CMV[8] := true;
        Break;
      end;
    end;
  end;

  { LIC 9: Three points separated by A_PTS and B_PTS that cannot fit in circle RADIUS1 }
  if NUMPOINTS >= 5 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
    begin
      j := i + PARAMETERS.A_PTS + 1;
      k := j + PARAMETERS.B_PTS + 1;
      if not CanFitInCircle(X[i], Y[i], X[j], Y[j], X[k], Y[k], PARAMETERS.RADIUS1) then
      begin
        CMV[9] := true;
        Break;
      end;
    end;
  end;

  { LIC 10: Three points separated by C_PTS and D_PTS form angle < PI-EPSILON or > PI+EPSILON }
  if NUMPOINTS >= 5 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.C_PTS - PARAMETERS.D_PTS - 2 do
    begin
      j := i + PARAMETERS.C_PTS + 1;
      k := j + PARAMETERS.D_PTS + 1;
      angle := CalcAngle(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
      if angle >= 0 then { Angle is defined }
      begin
        if (REALCOMPARE(angle, PI - PARAMETERS.EPSILON) = LT) or
           (REALCOMPARE(angle, PI + PARAMETERS.EPSILON) = GT) then
        begin
          CMV[10] := true;
          Break;
        end;
      end;
    end;
  end;

  { LIC 11: Three points separated by E_PTS and F_PTS form triangle with area > AREA1 }
  if NUMPOINTS >= 5 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
    begin
      j := i + PARAMETERS.E_PTS + 1;
      k := j + PARAMETERS.F_PTS + 1;
      area := TriangleArea(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
      if REALCOMPARE(area, PARAMETERS.AREA1) = GT then
      begin
        CMV[11] := true;
        Break;
      end;
    end;
  end;

  { LIC 12: Two points separated by G_PTS with X[j] - X[i] < 0 }
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.G_PTS - 1 do
    begin
      j := i + PARAMETERS.G_PTS + 1;
      if REALCOMPARE(X[j] - X[i], 0) = LT then
      begin
        CMV[12] := true;
        Break;
      end;
    end;
  end;

  { LIC 13: Two points separated by K_PTS with distance > LENGTH1 AND < LENGTH2 }
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
    begin
      j := i + PARAMETERS.K_PTS + 1;
      dist := Distance(X[i], Y[i], X[j], Y[j]);
      if REALCOMPARE(dist, PARAMETERS.LENGTH1) = GT then
      begin
        { Found first part, now check for second part }
        for k := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
        begin
          dist := Distance(X[k], Y[k], X[k + PARAMETERS.K_PTS + 1],
                          Y[k + PARAMETERS.K_PTS + 1]);
          if REALCOMPARE(dist, PARAMETERS.LENGTH2) = LT then
          begin
            CMV[13] := true;
            Break;
          end;
        end;
        if CMV[13] then
          Break;
      end;
    end;
  end;

  { LIC 14: Three points separated by A_PTS and B_PTS: cannot fit in RADIUS1 AND can fit in RADIUS2 }
  if NUMPOINTS >= 5 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
    begin
      j := i + PARAMETERS.A_PTS + 1;
      k := j + PARAMETERS.B_PTS + 1;
      if not CanFitInCircle(X[i], Y[i], X[j], Y[j], X[k], Y[k], PARAMETERS.RADIUS1) then
      begin
        { Found first part, now check for second part }
        for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
        begin
          j := i + PARAMETERS.A_PTS + 1;
          k := j + PARAMETERS.B_PTS + 1;
          if CanFitInCircle(X[i], Y[i], X[j], Y[j], X[k], Y[k], PARAMETERS.RADIUS2) then
          begin
            CMV[14] := true;
            Break;
          end;
        end;
        if CMV[14] then
          Break;
      end;
    end;
  end;

  { LIC 15: Three points separated by E_PTS and F_PTS: area > AREA1 AND area < AREA2 }
  if NUMPOINTS >= 5 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
    begin
      j := i + PARAMETERS.E_PTS + 1;
      k := j + PARAMETERS.F_PTS + 1;
      area := TriangleArea(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
      if REALCOMPARE(area, PARAMETERS.AREA1) = GT then
      begin
        { Found first part, now check for second part }
        for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
        begin
          j := i + PARAMETERS.E_PTS + 1;
          k := j + PARAMETERS.F_PTS + 1;
          area := TriangleArea(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
          if REALCOMPARE(area, PARAMETERS.AREA2) = LT then
          begin
            CMV[15] := true;
            Break;
          end;
        end;
        if CMV[15] then
          Break;
      end;
    end;
  end;

  { Compute PUM from CMV and LCM }
  for i := 1 to 15 do
  begin
    for j := 1 to 15 do
    begin
      if i = j then
        { Diagonal elements are input, don't modify }
        Continue
      else if LCM[i, j] = NOTUSED then
        PUM[i, j] := true
      else if LCM[i, j] = ANDD then
        PUM[i, j] := CMV[i] and CMV[j]
      else { ORR }
        PUM[i, j] := CMV[i] or CMV[j];
    end;
  end;

  { Compute FUV from PUM }
  for i := 1 to 15 do
  begin
    if not PUM[i, i] then
      { PUM[i,i] is false: LIC should not hold back launch }
      FUV[i] := true
    else
    begin
      { Check if all elements in row i are true }
      allTrue := true;
      for j := 1 to 15 do
      begin
        if not PUM[i, j] then
        begin
          allTrue := false;
          Break;
        end;
      end;
      FUV[i] := allTrue;
    end;
  end;

  { Compute LAUNCH decision }
  LAUNCH := true;
  for i := 1 to 15 do
  begin
    if not FUV[i] then
    begin
      LAUNCH := false;
      Break;
    end;
  end;
end;

end.
